export function t(key: keyof typeof T, lang: LangCode): string {
  const entry = T[key] as Record<string, string>;
  return entry[lang] ?? entry["en"] ?? entry["ko"];
}

/** 인라인 번역 헬퍼 — 전달한 언어만 있으면 되고, 없으면 en → ko 순 fallback */
export function tl(map: Partial<Record<LangCode, string>>, lang: LangCode): string {
  return map[lang] ?? map["en"] ?? map["ko"] ?? Object.values(map)[0] ?? "";
}
